  ('police-b20a8cf8-moex-00464', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '警方偵辦銀行強盜案件，研判犯罪人可能在案發前特定時段至現場附近觀察，調閱數天前之附近 監視器影像進行比對分析，以利取得更多歹徒面貌、特徵等資訊，此種監視器調閱方法為何？', '["特定目標比對法（TargetMatchingMethod）", "逐一畫面比對法（FramebyFrameAnalysisMethod）", "時間次序法（Time-SequenceMethod）", "時間區段比對法（Time-PeriodMatchingMethod）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00465', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '偵辦刑案過程中，若警方尚未發現被害人屍體，實務上可透過何種測謊技術，找出嫌疑人藏匿屍 體的可能區域？', '["區域比對法（ZoneComparisonTechnique）", "探索測試法（ExploratoryTest）", "緊張高點法（PeakofTensionTest）", "有關無關法（Relevant&IrrelevantTechnique）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00466', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '警方勘察一起室內槍擊命案，死者陳屍於房間地板上，天花板有數個彈孔，牆面有噴濺血跡，現 場留下一把手槍、數個彈殼以及數個未擊發子彈，並有一個已擊發之完整彈頭及數個碎裂彈頭之', '["以投影圖進行現場繪測，較平面圖更能呈 現現場狀況", "為避免破壞手槍表面跡證，以竹筷插入槍管將槍枝輕緩拿起進行採證", "完整彈 頭因遺留膛線痕跡等可供採證比對，碎裂彈頭碎片則無任何採證比對價值", "現場未擊發子彈可 用證物裝成一袋，並在外袋加以註記編號  ⑤若要採取死者手部射擊殘跡檢測，宜在案發後 12 小時以內儘速採集"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00467', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '根據「警察機關刑案證物管理注意事項」，除偵辦刑案、送請鑑定或移送檢察署等目的外，原則 禁止由個人保管刑案證物。若因特殊因素須由個人保管期間逾多久者，應事先經主管核准？', '["12小時", "16小時", "24小時", "36小時"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00468', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關「虛擬通貨平台及交易業務事業防制洗錢及打擊資恐辦法」之敘述，下列何者正確？', '["該辦法所稱之虛擬通貨包含數位型式新臺幣", "該辦法所稱之業者，不以在國內設立登記者為限", "該辦法所稱之業者，僅限提供虛擬通貨與新臺幣之交換服務，不包含虛擬通貨與其他外國貨幣 交換服務", "該辦法所稱之業者，包含為客戶保管虛擬通貨錢包私鑰之錢包商"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00469', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關偵查不公開，下列敘述何者錯誤？', '["偵查不公開原則應遵守人員，包含嫌疑人委任之辯護人", "司法警察得曉示被害人，如公開或揭露偵查中所知悉程序或內容對案件之可能影響", "案件在偵查中，對脫逃之嫌疑人經緝獲歸案，審酌公共利益及必要性等，警方得適度公開或揭 露偵查內容及偵查所得之心證", "少年犯罪事件亦有偵查不公開作業辦法之適用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00470', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關司法警察偵辦刑案執行搜索、扣押之規定，下列敘述何者正確？', '["司法警察受檢察官依刑事訴訟法第131條第2項指揮執行逕行搜索，執行完畢後應於12小時 內以密件封緘回報檢察官", "司法警察持搜索票執行搜索，發現本案應扣押之物為搜索票所未記載者，亦得扣押之，惟應於 執行扣押後2日內報告該管檢察官及法院", "偵查中辯護人得於搜索或扣押時在場，但認其在場對搜索或扣押有妨害者，不在此限", "司法警察持搜索票執行搜索時，無論受搜索人是否自願同意搜索，皆應出示證件並使用搜索票"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00471', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '有關跟蹤騷擾防制法，下列敘述何者正確？①跟蹤騷擾行為均為告訴乃論罪，需當事人提告才能', '["以電話、傳真等對特定人進行干擾，非屬跟蹤騷擾行為", "有跟蹤騷擾行為之犯罪 嫌疑者，警察機關應依職權或被害人請求，核發書面告誡予行為人", "曾有親密關係之未同居伴 侶間之跟蹤騷擾行為之保護令聲請，不適用該法保護令規定  ⑤保護令可由檢察官依職權向法 院聲請", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00472', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '查證犯罪嫌疑人之供述是否實在，下列何者為應注意情形？①嫌疑人是否具犯罪前科  ②供述是', '["供述是否與現場實際狀況吻合", "嫌疑人與共犯之間供詞是否矛盾 ⑤嫌疑人是否曾與辯護人接見", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 22, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL),
  ('police-b20a8cf8-moex-00473', 'police-b20a8cf8', 'police-b20a8cf8-moex-111-70902fa8', 'sub-police-b20a8cf8-04', NULL, 'single_choice', '販毒集團進行毒品販賣，由買賣雙方相約開車前往約定點見面，碰面後買主將車子交給賣主，由 賣主開買主車輛取貨，再將該車輛開至某處停放後返回原約定地點，將車輛鑰匙交還買主並告知 車輛停放位置，由買主前往取貨。實務上稱此種販毒模式為何？', '["跳蛙轉手", "活轉手", "多重轉手", "死轉手"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:24+00:00", "source_pdf_sha1": "4e3afb2db42f", "answer_pdf_sha1": "235894bbae73", "source_family": "moex-gov-tw", "moex": {"exam_code": "111070", "c": "503", "s": "1303", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "犯罪偵查學", "year": "111", "exam_name": "111年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、交通事業鐵路人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "刑事警察人員"}'::jsonb, NULL)
